# Confluence-specific boilerplate removal on top of the generic pipeline
from bs4 import BeautifulSoup, Tag
import unicodedata, re

CONFLUENCE_BOILERPLATE_SELECTORS = [
    "#header", "#footer", ".breadcrumb", ".page-metadata",
    ".plugin-tabmeta-details", "#comments-section",
    ".recently-updated", "#likes-and-labels-container",
]

def strip_confluence_boilerplate(html: str) -> str:
    soup = BeautifulSoup(html, "lxml")
    for sel in CONFLUENCE_BOILERPLATE_SELECTORS:
        for el in soup.select(sel):
            el.decompose()
    body = soup.find("div", {"id": "main-content"}) or soup
    return body.get_text(separator=" ")

def preprocess_confluence_page(html: str) -> str:
    text = strip_confluence_boilerplate(html)
    text = unicodedata.normalize("NFKC", text)
    text = re.sub(r"\s+", " ", text).strip()
    return text

