# RIGHT: single shared function
from preprocessing import preprocess   # used in both paths

from concurrent.futures import ProcessPoolExecutor
from typing import Iterable

def preprocess(text: str) -> str:
    import unicodedata, re
    from bs4 import BeautifulSoup
    text = unicodedata.normalize("NFKC", text)
    if "<" in text:
        text = BeautifulSoup(text, "lxml").get_text(separator=" ")
    return re.sub(r"\s+", " ", text).strip()

def batch_preprocess(documents: Iterable[str], workers: int = 8) -> list[str]:
    with ProcessPoolExecutor(max_workers=workers) as pool:
        return list(pool.map(preprocess, documents, chunksize=64))

import unicodedata

def strip_unicode_controls(text: str) -> str:
    """Remove Unicode format characters (bidirectional overrides, zero-width spaces, etc.)."""
    return "".join(
        ch for ch in text
        if unicodedata.category(ch) not in ("Cf", "Cs")
    )

# Use after NFKC:
def full_normalise(text: str) -> str:
    import unicodedata as ud
    text = ud.normalize("NFKC", text)
    text = strip_unicode_controls(text)
    return text
